jayess_value *jayess_glfw_set_window_fullscreen(jayess_value *window_value) {
    GLFWwindow *window = (GLFWwindow *) jayess_expect_native_handle(window_value, "GLFWwindow", "jayess_glfw_set_window_fullscreen");
    GLFWmonitor *monitor = NULL;
    const GLFWvidmode *mode = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    monitor = glfwGetPrimaryMonitor();
    if (monitor == NULL) {
        jayess_throw_error("glfwGetPrimaryMonitor failed");
        return jayess_value_undefined();
    }
    mode = glfwGetVideoMode(monitor);
    if (mode == NULL) {
        jayess_throw_error("glfwGetVideoMode failed");
        return jayess_value_undefined();
    }
    glfwSetWindowMonitor(window, monitor, 0, 0, mode->width, mode->height, mode->refreshRate);
    return jayess_value_undefined();
}

jayess_value *jayess_glfw_set_window_windowed(jayess_value *window_value, jayess_value *width_value, jayess_value *height_value) {
    GLFWwindow *window = (GLFWwindow *) jayess_expect_native_handle(window_value, "GLFWwindow", "jayess_glfw_set_window_windowed");
    int width = 0;
    int height = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    width = (int) jayess_value_to_number(width_value);
    height = (int) jayess_value_to_number(height_value);
    glfwSetWindowMonitor(window, NULL, 0, 0, width, height, GLFW_DONT_CARE);
    return jayess_value_undefined();
}

