    int mods = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    key = (int)jayess_value_to_number(key_value);
    action = (int)jayess_value_to_number(action_value);
    mods = (int)jayess_value_to_number(mods_value);
    _glfwInputKey((_GLFWwindow *)window, key, key, action, mods);
