jayess_value *jayess_glfw_is_joystick_present(jayess_value *joystick_value) {
    return jayess_value_from_bool(glfwJoystickPresent((int) jayess_value_to_number(joystick_value)));
}

jayess_value *jayess_glfw_is_joystick_gamepad(jayess_value *joystick_value) {
    return jayess_value_from_bool(glfwJoystickIsGamepad((int) jayess_value_to_number(joystick_value)));
}

jayess_value *jayess_glfw_get_joystick_name(jayess_value *joystick_value) {
    const char *name = glfwGetJoystickName((int) jayess_value_to_number(joystick_value));
    if (name == NULL || name[0] == '\0') {
        return jayess_value_undefined();
    }
    return jayess_value_from_string(name);
}

jayess_value *jayess_glfw_get_gamepad_name(jayess_value *joystick_value) {
    const char *name = glfwGetGamepadName((int) jayess_value_to_number(joystick_value));
    if (name == NULL || name[0] == '\0') {
        return jayess_value_undefined();
    }
    return jayess_value_from_string(name);
}

jayess_value *jayess_glfw_get_gamepad_button(jayess_value *joystick_value, jayess_value *button_value) {
    GLFWgamepadstate state;
    if (glfwGetGamepadState((int) jayess_value_to_number(joystick_value), &state) != GLFW_TRUE) {
        return jayess_value_undefined();
    }
    {
        int button = (int) jayess_value_to_number(button_value);
        if (button < 0 || button >= 15) {
            return jayess_value_undefined();
        }
        return jayess_value_from_bool(state.buttons[button] == GLFW_PRESS);
    }
}
